import fs from 'node:fs';
import path from 'node:path';
import crypto from 'node:crypto';

const orderPath = 'src/game/parts/_order.json';
if (!fs.existsSync(orderPath)) {
  console.error('Missing order file:', orderPath);
  process.exit(1);
}
const order = JSON.parse(fs.readFileSync(orderPath, 'utf8'));

if (!Array.isArray(order) || order.length < 5) {
  console.error('Bad _order.json. Det ligner ikke et spil, det ligner en ulykke.');
  process.exit(1);
}

const missing = [];
let source = '';
for (const file of order) {
  const p = path.join('src/game/parts', file);
  if (!fs.existsSync(p)) {
    missing.push(p);
    continue;
  }
  source += `\n\n/* ===== ${file} ===== */\n`;
  source += fs.readFileSync(p, 'utf8');
}
if (missing.length) {
  console.error('Missing part files:', missing.join(', '));
  process.exit(1);
}

const hash = crypto.createHash('sha256').update(source).digest('hex').slice(0, 12);
const banner = `/*\n  GRÅDIG: Dværgkast v14 Core Refactor Modular Bundle\n  Generated from src/game/parts. Do not edit this file directly.\n  Source hash: ${hash}\n*/\n`;

const bundle = `${banner}(() => {\n${source}\n})();\n`;

fs.mkdirSync('dist', { recursive: true });
fs.writeFileSync('dist/app.bundle.js', bundle, 'utf8');
fs.writeFileSync('dist/build-meta.json', JSON.stringify({
  version: 'v14-core-refactor',
  hash,
  parts: order,
  builtAt: new Date().toISOString()
}, null, 2), 'utf8');

console.log('Built dist/app.bundle.js from', order.length, 'parts');
console.log('Source hash:', hash);
